using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary.
    /// Defaults to 3 if not specified.
    /// </summary>
    [Range(1, 100)]
    public int? MaxSentences { get; set; }
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords =
    [
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "of", "for", "with", "by", "from", "as",
        "it", "its", "this", "that", "these", "those", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "can", "shall", "not", "no", "nor", "so",
        "if", "then", "than", "too", "very", "just", "about", "above", "after",
        "again", "all", "also", "am", "any", "because", "before", "between",
        "both", "each", "few", "he", "her", "here", "him", "his", "how", "i",
        "into", "me", "more", "most", "my", "myself", "now", "only", "other",
        "our", "out", "over", "own", "same", "she", "some", "such", "there",
        "they", "them", "their", "through", "under", "up", "we", "what",
        "when", "where", "which", "while", "who", "whom", "why", "you", "your"
    ];

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Take top-ranked sentences but preserve their original order
        var topIndices = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i].Trim()).ToList();
        var summary = string.Join(" ", summarySentences);

        return (summary, sentences.Count, summarySentences.Count);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            var words = ExtractWords(sentence);
            foreach (var word in words)
            {
                if (StopWords.Contains(word.ToLowerInvariant()) || word.Length < 2)
                    continue;

                var lower = word.ToLowerInvariant();
                frequencies[lower] = frequencies.GetValueOrDefault(lower) + 1;
            }
        }

        // Normalize by max frequency
        if (frequencies.Count > 0)
        {
            var max = frequencies.Values.Max();
            foreach (var key in frequencies.Keys)
            {
                frequencies[key] /= max;
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (var i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            double score = 0;
            int scoredWordCount = 0;

            foreach (var word in words)
            {
                var lower = word.ToLowerInvariant();
                if (wordFrequencies.TryGetValue(lower, out var freq))
                {
                    score += freq;
                    scoredWordCount++;
                }
            }

            // Normalize by word count to avoid bias toward long sentences
            if (scoredWordCount > 0)
                score /= scoredWordCount;

            // Slight boost for earlier sentences (lead bias)
            score *= 1.0 + (0.1 / (i + 1));

            scored.Add((i, score));
        }

        return scored;
    }

    private static List<string> ExtractWords(string sentence)
    {
        return WordExtractor()
            .Matches(sentence)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordExtractor();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizeController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var maxSentences = request.MaxSentences ?? 3;

        var (summary, originalCount, summaryCount) =
            _summarizationService.Summarize(request.DocumentText, maxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

